import{_ as t,c as o,o as d,ae as c}from"./chunks/framework.D5LTYjOy.js";const p=JSON.parse('{"title":"Alerts - AvAlert","description":"","frontmatter":{},"headers":[],"relativePath":"components/feedback/AvAlert/AvAlert.md","filePath":"components/feedback/AvAlert/AvAlert.md"}'),a={name:"components/feedback/AvAlert/AvAlert.md"};function r(l,e,i,s,n,h){return d(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="alerts-avalert" tabindex="-1">Alerts - <code>AvAlert</code> <a class="header-anchor" href="#alerts-avalert" aria-label="Permalink to &quot;Alerts - `AvAlert`&quot;">​</a></h1><h2 id="🌟-introduction" tabindex="-1">🌟 Introduction <a class="header-anchor" href="#🌟-introduction" aria-label="Permalink to &quot;🌟 Introduction&quot;">​</a></h2><p>The <code>AvAlert</code> component is an adaptation of the <code>DsfrAlert</code> code. It is intended for use in the <code>AvToaster</code> component.</p><p>Alerts draw the user attention to information without interrupting their current task.</p><p>The alert is available in two sizes:</p><ul><li>medium size (MD, by default, if the <code>small</code> prop is absent or set to <code>false</code>) and</li><li>small size (SM) if the <code>small</code> prop is set to <code>true</code>.</li></ul><p>🏅 The documentation for <code>DsfrAlert</code> can be found at <a href="https://vue-ds.fr/composants/DsfrAlert" target="_blank" rel="noreferrer">VueDSFR</a></p><h2 id="📐-structure" tabindex="-1">📐 Structure <a class="header-anchor" href="#📐-structure" aria-label="Permalink to &quot;📐 Structure&quot;">​</a></h2><p>The alert consists of the following elements:</p><ul><li>a title (prop <code>title</code>, of type <code>string</code>): <ul><li>mandatory on the MD version (if the <code>small</code> prop is absent or set to <code>false</code>),</li><li>optional on the SM version (if the <code>small</code> prop is set to <code>true</code>).</li></ul></li><li>an icon and a color determined by the <code>type</code> prop, which can be one of the following strings: <ul><li><code>info</code> (default value if the <code>type</code> prop is absent)</li><li><code>success</code></li><li><code>warning</code></li><li><code>error</code></li></ul></li><li>a description text (with the <code>description</code> prop, of type <code>string</code>): <ul><li>optional on the MD version</li><li>mandatory on the SM version</li><li>the default <code>slot</code> can be used as a description</li></ul></li><li>a closing cross if the <code>closeable</code> prop is set to <code>true</code></li></ul><p>Other props:</p><ul><li><code>closed</code> is used to indicate whether the alert should be present (<code>false</code>) or not (<code>true</code>) in the DOM.</li><li><code>titleTag</code> specifies the tag to use for the <code>title</code>: this is <code>h3</code> by default, however, to pass RGAA tests, the heading levels must be consecutive and consistent (for example, if there is no <code>&lt;h2&gt;</code> on the page, you must pass <code>&#39;h2&#39;</code> as the value to the <code>titleTag</code> prop so that the modal title is <code>&lt;h2&gt;</code>).</li><li><code>closeButtonLabel</code> specifies the label and aria-label of the alert close button. By default, the value is <code>Close</code>.</li></ul><h2 id="🛠️-props" tabindex="-1">🛠️ Props <a class="header-anchor" href="#🛠️-props" aria-label="Permalink to &quot;🛠️ Props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Type</th><th>Default</th><th>Mandatory</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>string</code></td><td><code>crypto.randomUUID()</code></td><td></td><td>The alert ID.</td></tr><tr><td><code>type</code></td><td><code>&#39;info&#39; | &#39;success&#39; | &#39;warning&#39; | &#39;error&#39;</code></td><td><code>&#39;info&#39;</code></td><td></td><td>The alert type influences its color and associated icon.</td></tr><tr><td><code>title</code></td><td><code>string</code></td><td><code>&#39;&#39;</code></td><td></td><td>The alert title.</td></tr><tr><td><code>description</code></td><td><code>string</code></td><td><code>undefined</code></td><td></td><td>The alert description text.</td></tr><tr><td><code>titleTag</code></td><td><code>&#39;h1&#39; | &#39;h2&#39; | &#39;h3&#39; | &#39;h4&#39; | &#39;h5&#39; | &#39;h6&#39;</code></td><td><code>&#39;h3&#39;</code></td><td></td><td>The tag to use for the alert title.</td></tr><tr><td><code>small</code></td><td><code>boolean</code></td><td><code>false</code></td><td></td><td>Indicates whether the alert should be MD (<code>false</code>) or SM (<code>true</code>) in version.</td></tr><tr><td><code>closed</code></td><td><code>boolean</code></td><td><code>false</code></td><td></td><td>Indicates whether the alert should be present (<code>false</code>) or not (<code>true</code>) in the DOM.</td></tr><tr><td><code>closeable</code></td><td><code>boolean</code></td><td><code>false</code></td><td></td><td>Indicates whether the close button should be present (<code>true</code>) or not (<code>false</code>) in the alert.</td></tr><tr><td><code>closeButtonLabel</code></td><td><code>string</code></td><td><code>&#39;Close&#39;</code></td><td></td><td>The label and aria-label of the alert close button.</td></tr><tr><td><code>alert</code></td><td><code>boolean</code></td><td><code>false</code></td><td></td><td>Indicates whether the alert should have the <code>alert</code> role (<code>true</code>) or not (<code>false</code>).</td></tr></tbody></table><h2 id="📡-events" tabindex="-1">📡 Events <a class="header-anchor" href="#📡-events" aria-label="Permalink to &quot;📡 Events&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Data (<em>payload</em>)</th><th>Description</th></tr></thead><tbody><tr><td><code>&#39;close&#39;</code></td><td></td><td>Event triggered when the alert is closed.</td></tr></tbody></table><h2 id="🧩-slots" tabindex="-1">🧩 Slots <a class="header-anchor" href="#🧩-slots" aria-label="Permalink to &quot;🧩 Slots&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Description</th></tr></thead><tbody><tr><td><code>default</code></td><td>Default slot for alert description.</td></tr></tbody></table>',18)])])}const f=t(a,[["render",r]]);export{p as __pageData,f as default};
